const items = $('👂 Fetch Chat').first().json.items; 
const memory = $input.all(); 

if (!items || items.length === 0) return [];

const MY_BOT_NAMES = [
  "NoahStationMaster", "Neon_GlitchMode", "Noah Station", "Neon",
  "@NoahStationMaster", "@Neon_GlitchMode", "@เสียงของสิ่งที่ไม่พูด"
];

const MAX_TIME_DIFF_MS = 90000; 
const now = new Date().getTime();
let queue = [];

const repliedFingerprints = memory.map(m => (m.json.Author + "||" + m.json.Message).toLowerCase());
const seenAuthorsInThisBatch = new Set(); // 🛡️ ANTI-SPAM: กฎเหล็ก 1 คน / 1 ข้อความ / 1 รอบ

for (const msg of items) {
  if (!msg.snippet || !msg.authorDetails) continue;

  const author = msg.authorDetails.displayName;
  const msgTime = new Date(msg.snippet.publishedAt).getTime();
  const text = msg.snippet.displayMessage;
  const currentFingerprint = (author + "||" + text).toLowerCase();

  if (MY_BOT_NAMES.includes(author)) continue;
  if (now - msgTime > MAX_TIME_DIFF_MS) continue;
  if (repliedFingerprints.includes(currentFingerprint)) continue;

  // 🛑 SPAM BLOCKER: ถ้ายูสเซอร์คนนี้โผล่มาแล้วในรอบนี้ (แปลว่ากำลังสแปมรัวๆ) ดีดข้อความใหม่ทิ้งทันที!
  if (seenAuthorsInThisBatch.has(author)) continue;
  seenAuthorsInThisBatch.add(author);

  queue.push({
    messageId: msg.id,
    author: author,
    channelId: msg.authorDetails.channelId,
    message: text,
    publishedAt: msg.snippet.publishedAt,
    liveChatId: msg.snippet.liveChatId
  });
}

// 🚦 จัดคิว: ดึงแชทเก่าสุดขึ้นมาก่อน และจำกัดโควต้าคิวรวมที่ 3 ข้อความ
queue.reverse();
return queue.slice(0, 3).map(q => ({ json: q }));

