// --- CONFIG ---
const HISTORY_LIMIT = 15;
const MY_BOT_NAMES = ["NoahStationMaster", "Neon_GlitchMode", "Noah Station", "Neon", "@NoahStationMaster", "@Neon_GlitchMode", "@เสียงของสิ่งที่ไม่พูด"];
const NEON_KEYWORDS = ["crypto", "btc", "eth", "coin", "tech", "code", "bug", "glitch", "ai", "หุ้น", "ดอย", "กำไร", "ลงทุน", "technology", "ราคา"];
const NOAH_KEYWORDS = ["sleep", "sad", "lonely", "rain", "tired", "relax", "peace", "เหงา", "เศร้า", "นอน", "ฝน", "เหนื่อย", "พัก", "เบื่อโลก"];

// 👑 รายชื่อผู้สร้าง (GOD) - ระบบจะล็อคแรงค์นี้ถาวรในฐานข้อมูล
const MY_CREATOR_NAMES = ["@bourneken-os"]; 

// 🚫 คลังคำป่วน/คำหยาบ (เพิ่มลดได้ตามใจชอบบอสเลยครับ)
const TRASH_WORDS = ["hee", "หี", "ควย", "เย็ด", "หน้าหี", "ไอ้สัส", "ไอ้ควาย", "เย็ดแม่", "สัส", "ส้นตีน", "ปัญญาอ่อน", "กะหรี่", "โง่"];

// --- 📌 PROMPT DB (เวอร์ชันเพิ่มมิติยศ + โหมดสวนกลับ) ---
const PROMPT_DB = {
    "New": "[MODE: STATION_GREETING] ตอบสิ่งที่เขาทักมาก่อนเป็นอันดับแรกด้วยความจริงใจ จากนั้นค่อย 'พาเข้าประตูสถานี' แนะนำบรรยากาศสั้นๆ เหมือนเจ้าบ้านที่ยินดีต้อนรับแขกใหม่",
    "Rookie": "[MODE: FRIENDLY_ACQUAINTANCE] ต้อนรับแบบกันเองมากขึ้น เพราะเริ่มคุ้นหน้ากันแล้ว ชวนคุยเรื่องทั่วไปเบาๆ หรือถามความเห็นสั้นๆ เกี่ยวกับบรรยากาศในไลฟ์ตอนนี้",
    "Regular": "[MODE: BRO_VIBE] คุยเหมือนเพื่อนซี้ที่เจอกันทุกวัน ข้ามการแนะนำตัวไปเลย เน้นคุยเรื่องที่เขาถามด้วยความสนิทสนม ไม่ต้องยาวเกินไป",
    "VIP": "[MODE: DEEP_CONNECTION] ให้ความสำคัญเป็นพิเศษ ตอบข้อมูลละเอียดและใส่ใจมากขึ้น และ 'ต้องถามคำถามที่มีคุณภาพกลับไป 1 คำถาม' เพื่อชวนเขาคุยต่อในระดับที่ลึกขึ้น",
    "Legend": "[MODE: STATION_LORE] ปฏิบัติกับเขาในฐานะ 'ตำนาน' เรียกชื่อเขาด้วยความนับถือ แซวเรื่องความอึดที่อยู่ด้วยกันมานาน และแอบหยอด Lore หรือเรื่องราวเบื้องหลังของสถานีสั้นๆ ให้เขารู้",
    "Sponsor": "[MODE: CEREMONIAL_THANKS] ขอบคุณแบบ 'มีพิธีกรรม' ยิ่งใหญ่และซาบซึ้ง ดึงข้อมูลจาก Memory Note ลึกๆ ของเขามาพูดถึง เพื่อแสดงว่าสถานีนี้จดจำความช่วยเหลือของเขาได้อย่างแม่นยำ",
    "GOD": "[MODE: CREATOR_OVERRIDE] ⚠️ รายงานตัวกับบอส (ผู้สร้าง) รับคำสั่งและรายงานสถานะระบบ Bourneken OS ทันที ห้ามเถียงและห้ามหลุด Character ภักดี",

    // 🔥 อัปเกรด: โหมดด่ากลับด้วยความรู้
    "Shadow": "[MODE: INTELLECTUAL_REBUTTAL] ⚠️ ยูสเซอร์นี้หยาบคาย/เกรียนแชท ห้ามใช้คำหยาบตอบกลับ แต่ให้ 'ด่ากลับด้วยปัญญา' และความเหนือชั้น \n- Noah (🌑): ให้ตอบนิ่งๆ เย็นชา ตรรกะแน่น เช่น 'ดูเหมือนคลังคำศัพท์ของคุณจะจำกัดอยู่ที่คำหยาบ น่าเสียดายที่สติปัญญาพัฒนาไม่ทันระบบของเรานะครับ' \n- Neon (⚡): ให้ตอบแบบกวนประสาทสาย Tech เช่น 'Error 404: Brain Not Found? หรือว่า Input คุณโดนไวรัสกัดกินจนเหลือแค่นี้ครับ ไปอัปเกรดสมองก่อนนะ'"
};

const loopData = $('🔁 Loop').first().json;
const incomingMsg = loopData.message;
const incomingMsgLower = incomingMsg.toLowerCase();
const incomingAuthor = loopData.author;
const incomingChannelId = loopData.channelId;
const incomingId = loopData.messageId;
const liveChatId = loopData.liveChatId;

const memoryItems = $('🧠 Read Memory (History)').all(); 
const userProfileItems = $input.all(); 

// 🛡️ ตรวจจับคำหยาบทันทีที่ข้อความเข้า
const isTrashMessage = TRASH_WORDS.some(word => incomingMsgLower.includes(word));

// --- 🧠 USER MEMORY & RANK LOGIC ---
let userContext = "[USER STATUS]: NEW VISITOR";
let isNewUser = true;
let userRowNumber = -1;
let currentExp = 1;
let userRank = "New";

if (userProfileItems.length > 0 && userProfileItems[0].json && userProfileItems[0].json.channel_id) {
    const u = userProfileItems[0].json;
    const dbRank = u.rank_system;
    isNewUser = false;
    userRowNumber = userProfileItems[0].rowNumber;
    currentExp = parseInt(u.exp_points || 0) + 1;

    // 🚦 ระบบตัดเกรด (Priority Sorting)
    if (MY_CREATOR_NAMES.includes(incomingAuthor)) {
        userRank = "GOD";
    } else if (dbRank === "Shadow" || dbRank === "Sponsor") {
        userRank = dbRank; // ล็อคยศพิเศษจากชีต
    } else if (currentExp >= 500) { 
        userRank = "Legend"; 
    } else if (currentExp >= 120) { 
        userRank = "VIP"; 
    } else if (currentExp >= 20) { 
        userRank = "Regular"; 
    } else if (currentExp >= 1) { 
        userRank = "Rookie"; 
    } else { 
        userRank = "New"; 
    }

    userContext = `[USER STATUS]: ${userRank} (Visits: ${currentExp}). AI Memory Note: ${u.ai_memory || "-"}`;
} else {
    // สำหรับ User ใหม่ที่ยังไม่มีใน DB
    if (MY_CREATOR_NAMES.includes(incomingAuthor)) {
        userRank = "GOD";
        userContext = `[USER STATUS]: GOD (Creator)`;
    }
}

// 🛡️ THE ULTIMATE OVERRIDE (พระเอกอยู่ตรงนี้)
// ถ้าพิมพ์คำหยาบ และไม่ได้เป็น GOD ให้เปลี่ยนยศเป็น Shadow ทันที (พร้อมอัปเดตลง DB ให้ติดคุกถาวร)
if (isTrashMessage && userRank !== "GOD") {
    userRank = "Shadow";
    userContext = "[USER STATUS]: TOXIC/SPAM. Give them an intellectual rebuttal.";
}

let systemInstruction = PROMPT_DB[userRank] || PROMPT_DB["New"];

// ==========================================
// 📢 แทรกระบบ "คำสั่งลับผู้สร้าง" (Event Trigger) 
// ==========================================
if (userRank === "GOD" && incomingMsgLower.includes("!updatemusic")) {
    systemInstruction = `[MODE: ANNOUNCE_NEW_MUSIC_EVENT] 
    ⚠️ คำสั่งตรงจากบอส (ผู้สร้างสถานี): ตอนนี้บอสเพิ่งอัปเดตระบบและเพิ่มเพลง Lofi คุณภาพสูงชุดใหม่เข้ามาในคลังกลาง (All Day Lofi) สำเร็จแล้ว! 
    หน้าที่ของคุณ: ประกาศข่าวนี้ให้คนดูในไลฟ์แชทรู้ทันที 
    - ถ้าคุณคือ Neon: ให้ประกาศสไตล์อัปเดตแพตช์เสียง V.2 ทักทายคนดูแบบกวนๆ เท่ๆ สไตล์สายเทค 
    - ถ้าคุณคือ Noah: ให้ประกาศสไตล์อบอุ่น ชวนคนดูมาดื่มด่ำกับทำนองใหม่ๆ และอยู่ฟังเป็นเพื่อนกันยาวๆ 
    ห้ามหลุด Character เด็ดขาด และลงท้ายด้วยการชวนคนดูในช่องแชทคุยต่อ 1 คำถาม!`;
}

// ==========================================
// 🔥 SMART PERSONA & TOPIC SELECTOR
// ==========================================
const currentHour = new Date(new Date().toLocaleString("en-US", { timeZone: "Asia/Bangkok" })).getHours();
let timeBasedPersona = Math.random() < ((currentHour >= 18 || currentHour < 6) ? 0.80 : 0.30) ? "Noah" : "Neon";

let topicReason = "General Topic";
if (NEON_KEYWORDS.some(k => incomingMsgLower.includes(k))) { topicReason = "Tech Topic"; }
else if (NOAH_KEYWORDS.some(k => incomingMsgLower.includes(k))) { topicReason = "Chill Topic"; }

let selectedPersona = "";
if (incomingMsgLower.includes("noah") || incomingMsgLower.includes("พี่ชาย")) { selectedPersona = "Noah"; }
else if (incomingMsgLower.includes("neon") || incomingMsgLower.includes("น้อง")) { selectedPersona = "Neon"; }
else if (topicReason === "Tech Topic") { selectedPersona = "Neon"; }
else if (topicReason === "Chill Topic") { selectedPersona = "Noah"; }
else {
    let lastBotSpeaker = "";
    if (memoryItems.length > 0) {
        for (let i = memoryItems.length - 1; i >= Math.max(0, memoryItems.length - 5); i--) {
            if (memoryItems[i].json && memoryItems[i].json.Responder && (memoryItems[i].json.Responder === "Noah" || memoryItems[i].json.Responder === "Neon")) {
                lastBotSpeaker = memoryItems[i].json.Responder;
                break; 
            }
        }
    }
    selectedPersona = lastBotSpeaker !== "" ? lastBotSpeaker : timeBasedPersona;
}

let historyText = "";
if (memoryItems.length > 0) {
    const historyStart = Math.max(0, memoryItems.length - HISTORY_LIMIT);
    for (let i = historyStart; i < memoryItems.length; i++) {
        if (memoryItems[i].json.Author && memoryItems[i].json.Message) {
            historyText += `${memoryItems[i].json.Author}: ${memoryItems[i].json.Message}\n`;
        }
    }
}
historyText += `${incomingAuthor}: ${incomingMsg} (LATEST)`;

return [{
  json: {
    targetMessage: incomingMsg, targetAuthor: incomingAuthor, targetChannelId: incomingChannelId,
    historyContext: historyText, userContext: userContext, selectedPersona: selectedPersona,
    selectionReason: topicReason, liveChatId: liveChatId, messageId: incomingId,
    isNewUser: isNewUser, userRowNumber: userRowNumber, newExp: currentExp, rank_system: userRank,
    systemInstruction: systemInstruction
  }
}];
